module sr_latch (
    input SR_LATCH_S,
    input R,
    output reg Q,
    output reg Qn
);
    always @ (SR_LATCH_S or R) begin
        if (SR_LATCH_S && !R) begin
            Q = 1;
            Qn = 0;
        end else if (!SR_LATCH_S && R) begin
            Q = 0;
            Qn = 1;
        end else if (!SR_LATCH_S && !R) begin
            // Maintain previous state
            Q = Q;
            Qn = Qn;
        end else begin
            // Invalid state
            Q = 1'bx;
            Qn = 1'bx;
        end
    end
endmodule
